#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    int *l = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &l[i]);
    }

    qsort(l, n, sizeof(int), compare);

    int count = 0;

    if (k >= m) {
        count = 0;
    } else {
        for (int i = 0; i < n; i++) {
            count++;
            k += (l[i] - 1);
            if (k >= m) {
                break;
            }
            if ((k == 0 || l[i] == 1) || k == 0) {
                count = -1;
                break;
            }
        }
        if (k < m) {
            count = -1;
        }
    }

    printf("%d\n", count);
    free(l);
    return 0;
}
